def _get_env(name, default=None):
    value = os.environ.get(name, default)
    if value is None or value == "":
        raise ValueError(f"Missing required environment variable: {name}")
    return value


def _detect_content_type(key):
    key_lower = key.lower()
    if key_lower.endswith(".jpg") or key_lower.endswith(".jpeg"):
        return "image/jpeg"
    if key_lower.endswith(".png"):
        return "image/png"
    if key_lower.endswith(".gif"):
        return "image/gif"
    if key_lower.endswith(".webp"):
        return "image/webp"
    if key_lower.endswith(".bmp"):
        return "image/bmp"
    if key_lower.endswith(".tiff") or key_lower.endswith(".tif"):
        return "image/tiff"
    return "application/octet-stream"


def process_image(image_bytes, key):
    result = {
        "source_key": key,
        "size_bytes": len(image_bytes),
        "status": "processed",
    }
    return json.dumps(result, indent=2).encode("utf-8")


def lambda_handler(event, context):
    logger.info("Received event: %s", json.dumps(event))

    output_bucket = _get_env("OUTPUT_BUCKET")
    sns_topic_arn = os.environ.get("SNS_TOPIC_ARN")
    output_prefix = os.environ.get("OUTPUT_PREFIX", "processed/")

    records = event.get("Records", [])
    if not records:
        logger.warning("No records found in event")
        return {"statusCode": 400, "body": json.dumps({"message": "No records found"})}

    results = []

    for record in records:
        try:
            bucket = record["s3"]["bucket"]["name"]
            key = unquote_plus(record["s3"]["object"]["key"])
            logger.info("Processing file s3://%s/%s", bucket, key)

            obj = s3.get_object(Bucket=bucket, Key=key)
            image_bytes = obj["Body"].read()

            processed_bytes = process_image(image_bytes, key)

            base_name = key.rsplit("/", 1)[-1]
            output_key = f"{output_prefix.rstrip('/')}/{base_name}.json"

            s3.put_object(
                Bucket=output_bucket,
                Key=output_key,
                Body=processed_bytes,
                ContentType="application/json",
            )

            logger.info("Wrote processed result to s3://%s/%s", output_bucket, output_key)

            notification_message = {
                "source_bucket": bucket,
                "source_key": key,
                "output_bucket": output_bucket,
                "output_key": output_key,
                "status": "success",
            }

            if sns_topic_arn:
                sns.publish(
                    TopicArn=sns_topic_arn,
                    Subject="Image processing complete",
                    Message=json.dumps(notification_message),
                )
                logger.info("Sent SNS notification to %s", sns_topic_arn)

            results.append(
                {
                    "source_bucket": bucket,
                    "source_key": key,
                    "output_bucket": output_bucket,
                    "output_key": output_key,
                    "status": "success",
                }
            )

        except ClientError as e:
            logger.exception("AWS client error while processing record")
            error_message = str(e)
            if sns_topic_arn:
                try:
                    sns.publish(
                        TopicArn=sns_topic_arn,
                        Subject="Image processing failed",
                        Message=json.dumps(
                            {
                                "status": "failure",
                                "error": error_message,
                                "record": record,
                            }
                        ),
                    )
                except Exception:
                    logger.exception("Failed to send SNS failure notification")
            results.append({"status": "failure", "error": error_message})
        except Exception as e:
            logger.exception("Unexpected error while processing record")
            error_message = str(e)
            if sns_topic_arn:
                try:
                    sns.publish(
                        TopicArn=sns_topic_arn,
                        Subject="Image processing failed",
                        Message=json.dumps(
                            {
                                "status": "failure",
                                "error": error_message,
                                "record": record,
                            }
                        ),
                    )
                except Exception:
                    logger.exception("Failed to send SNS failure notification")
            results.append({"status": "failure", "error": error_message})

    return {
        "statusCode": 200,
        "body": json.dumps({"results": results}),
    }